#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use File::Basename;

my $log_dir = '/path/to/log/directory';
my $cgi = new CGI;

my $filename = param('logfile');
if (!$filename) {
    print header("text/html");
    print start_html(-title => 'Log Viewer');
    print "Please provide a log file name.";
    print end_html;
    exit;
}

open(my $FH, "<$log_dir/$filename") or die "Can't open $filename: $!";
my @lines = <$FH>;
close($FH);

print header("text/html");
print start_html(-title => 'Log Viewer');
print h1('Log File: ', $filename);
print table({border => 0}, map {tr(b, $_) for split /\n/, $_} @lines);
print end_html;